// Script Continued Below
var templatesMap = {};
	var	nameIter = {};
		getRecords();

		function getRecords(){
			var gr = new GlideRecord("x_153465_discovert_discover_routing_template");
			gr.query();
			while(gr.next()){
				var templateName = gr.template_name.toString().toLowerCase();
				var trackChange = false;
				if(templatesMap[templateName]){
					var num = ++nameIter[templateName];
					var changedName = gr.template_name +  ' - Copy (' + num +')';
					gr.template_name = changedName;
					trackChanges = true;
				}else{
					templatesMap[templateName] = true;
					nameIter[templateName] = 0;
				}
				if(trackChange) {		
					gr.update();
				}
			}
		}
